INSERT INTO "public"."words_a" ("id", "word", "phonetic", "meaning", "created_at", "example", "translation", "example_translation", "example_image_url", "example_audio_url") VALUES ('42', 'applause', '/əˈplɔːz/', '鼓掌、喝彩；称赞(u)', '2026-04-21 20:04:00.209556', 'The audience gave loud applause.', null, '观众热烈鼓掌。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/applause_1778231536731_85fc0b8b.png?sign=1780823537-8f3f6ff121-0-82fa0d239510545247fa7f705112e8b3c0ebfb911153e3d54e2ebd2c24fafa1e', null), ('43', 'pinch', '/pɪntʃ/', '捏、掐(c, vt)；一撮、少量(c)；困苦(u)；逮捕(vt)；(穿的鞋等)夹痛(v)', '2026-04-21 20:04:00.209556', 'She pinched my arm gently.', null, '她轻轻掐了我的胳膊。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-videos/pinch_1778231646319_20019dca.mp4?sign=1780823647-5f8f4b245c-0-0beb6427de20d68330b3850df74507697582479f34505ff4d320f3a0df6cc0cc', null), ('54', 'belly', '/ˈbeli/', '腹部；(物体的)圆形或凸起部分(c)；(使)(帆)鼓起(v)', '2026-04-21 20:04:00.209556', 'The baby patted its soft belly.', null, '婴儿拍了拍它柔软的腹部。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-videos/belly_1778231909577_34a72a7b.mp4?sign=1780823910-87d251b6e1-0-99705d347bff3f52114a378108b0ec96dc9bea55a3c15d4b120cacaf1bfdfa3e', null), ('55', 'stomach', '/ˈstʌmək/', '胃(部)(c)；胃口(n)；忍受(vt)', '2026-04-21 20:04:00.209556', 'I feel my stomach ache now', null, '我现在感觉胃痛

例句: The smell kills my stomach
翻译: 这气味让我倒胃口

例句: I can''t stomach his lies
翻译: 我无法忍受他的谎言', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/stomach_1778231854435_5181acdc.png?sign=1780823854-99f7528083-0-ee689d6d50c035a7b45c0b0381b0b50bb57cc02ebd21e336ffcaccc3c3308261', null), ('56', 'bowel', '/ˈbaʊəl/', '肠(c, usually pl)；内部最深处(pl, the bowels of sth)', '2026-04-21 20:04:00.209556', 'She cleansed her bowels daily.', null, '她每天清洗肠道。

例句: We explored the bowels of the cave.
翻译: 我们探索了洞穴的内部最深处。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/bowel_1778231880869_87ba5949.png?sign=1780823881-00d62108ea-0-ec037f98490f5e8ed8504ca0ae1aa357468974958b3112903f631caae521a3f6', null), ('57', 'waist', '/weɪst/', '(人或衣服的)腰、腰部(c)', '2026-04-21 20:04:00.209556', 'She measured her waist today.', null, '她今天量了自己的腰围。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/waist_1778231938488_d092c642.png?sign=1780823939-cb44437c17-0-4f54837bb45d51e0afd2689450e798ed52e8381c4283a77dee0de78744f5db95', null), ('58', 'hip', '/hɪp/', '髋、臀部(c)', '2026-04-21 20:04:00.209556', 'She hurt her hip yesterday.', null, '她昨天伤到了髋部。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/hip_1778231960627_aa7c98a3.png?sign=1780823961-84a4eb3ef3-0-834caa04756c68365e92cda9dab4303cdb0695bbecbe23e5ec7182b5c8685f3b', null), ('59', 'appendix', '/əˈpendɪks/', '阑尾；(书、文件的)附录；附属物(c)', '2026-04-21 20:04:00.209556', 'The doctor removed his appendix.', null, '医生切除了他的阑尾。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/appendix_1778231990104_3c53d6ef.png?sign=1780823990-a918d4e46f-0-e230d7fbfdbe4bd44f8ea958bbd0baabe9cb423dd753ce2c58f0c401f36143de', null), ('60', 'leg', '/leɡ/', '(人、裤子、桌子等的)腿(c)；跑(vi)', '2026-04-21 20:04:00.209556', 'She crossed her legs gently.', null, '她轻轻交叉双腿。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/leg_1778232008357_1af3c5bf.png?sign=1780824008-64c89cce80-0-b811cd6d92d42a3c6599bd9cf0ca7c1b39ded8cf15a20cafc370a6db2ad96432', null), ('61', 'thigh', '/θaɪ/', '大腿；(供食用的禽类的)腿(c)', '2026-04-21 20:04:00.209556', 'She rubbed her sore thigh gently.', null, '她轻轻揉了揉酸痛的大腿。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/thigh_1778232028439_9a878de3.png?sign=1780824028-7f1ebe2ced-0-f8e1392edc653722faffd2cc66e09b42a47de3057eec13c715b2ac6c2253c8d1', null), ('62', 'knee', '/niː/', '膝盖、膝关节；(裤子的)膝部(c)', '2026-04-21 20:04:00.209556', 'She hit her knee on the table.', null, '她的膝盖撞到了桌子上。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/knee_1778232058369_870a2c97.png?sign=1780824059-75eb14a407-0-e93180617e5fcdce061ae2f7833348445bd285844953b6d4fee0623f1ea55ecf', null), ('66', 'heel', '/hiːl/', '(脚、鞋、袜等的)后跟(c)；倾斜(phr v, ~ over)', '2026-04-21 20:04:00.209556', 'She repaired her shoe''s heel.', null, '她修好了她鞋子的后跟。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/heel_1778232090115_8c526737.png?sign=1780824090-4ac9d9d1fa-0-a559ea1987696fefb1de062fa892ec84cc361bed59e26ab49eaf85b9b0ee1a21', null), ('69', 'remains', '/rɪˈmeɪnz/', '遗体；遗迹；剩余物(如剩饭剩菜)(plural)', '2026-04-21 20:04:00.209556', 'The archaeologists found ancient remains.', null, '考古学家发现了古老遗迹。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/remains_1778232227009_56a058f1.png?sign=1780824227-268d1fe843-0-254de4b59f26b73ef0f7649cbe4341ef09b6c578dce1bafa65fd2cbb0de92e67', null), ('71', 'skeleton', '/ˈskelɪtn/', '骨架、骨骼；(建筑的)骨架(c)；纲要(c, usually sing)；骨骼的', '2026-04-21 20:04:00.209556', 'The old building''s skeleton remains strong.', null, '这座旧建筑的骨架依然坚固。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/skeleton_1778232256398_0226b633.png?sign=1780824256-2bcddf7bd1-0-5642ba7162737194898af79fefb69821952f0fadc770260c36b7faaf9141015a', null), ('72', 'joint', '/dʒɔɪnt/', '关节；接头、接缝、结合处(c)；(用接头等)结合(vt)；共同的、联合的(only before noun)', '2026-04-21 20:04:00.209556', 'We wrap the joint with tape.', null, '我们用胶带包裹这个接头。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/joint_1778232394455_fa11c563.png?sign=1780824395-ac79b720be-0-b20a98f1735348708bc72a60be40611371e22531f9f3cc61d6e18a48a0f2f347', null), ('73', 'skin', '/skɪn/', '皮肤、(动物、果蔬的)皮(n)；剥去…的皮(vt)', '2026-04-21 20:04:00.209556', 'She applies cream to her skin.', null, '她往皮肤上涂面霜。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/skin_1778232417203_ab1a8488.png?sign=1780824418-f23f94e260-0-9876204a5d41a5391d0541de25107e6a02fe585ef13ce3b9860b32ecc0059217', null), ('75', 'artery', '/ˈɑːrtəri/', '动脉；(河流、公路等的)干线(c)', '2026-04-21 20:04:00.209556', 'A blocked artery causes health risks.', null, '一条堵塞的动脉会带来健康风险。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/artery_1778232441836_b5bb185f.png?sign=1780824442-2d56f1e702-0-b31fd4e3f14dc86697af33b41eb5337803a7da2625108a2a6efb8263e6ad0ba7', null), ('76', 'vein', '/veɪn/', '静脉；翅脉、叶脉；(木头、石头等的)纹理(c)', '2026-04-21 20:04:00.209556', 'The doctor injected medicine into her vein', null, '医生将药物注射进她的静脉', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/vein_1778232469004_757944c6.png?sign=1780824469-57b332caf3-0-868c790e7ebb3cfc5378315ca1b79a242c62b46576f85c7feea55b46328d6d60', null), ('77', 'nerve', '/nɜːrv/', '神经(c)；神经质(pl)；勇气(u)；鼓足勇气(vt, ~ yourself to do sth)', '2026-04-21 20:04:00.209556', 'She felt a nerve twitch in her leg', null, '她感到腿上的一根神经在抽搐

例句: His nerves calmed after the test
翻译: 考试后他的神经质症状缓解了

例句: He had the nerve to speak up
翻译: 他有勇气站出来说话

例句: She nerved herself to enter the room
翻译: 她鼓足勇气走进房间', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/nerve_1778232527668_49ad6a91.png?sign=1780824528-ffbe1826db-0-2487ea4abedcef1dd871bcd4e663d82c8fb3c582929ca4b5677f37d60fed0e9b', null), ('78', 'cell', '/sel/', '细胞；电池；单人牢房(c)', '2026-04-21 20:04:00.209556', 'A plant cell contains chloroplasts.', null, '植物细胞含有叶绿体。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/cell_1778232552401_83ce3531.png?sign=1780824552-d92dbd0b07-0-9525f1c5eae64c441eff3c69009d4009d8d0d07a6d78936fd42aa5d6499e59db', null), ('79', 'attribute', '/əˈtrɪbjuːt/', '(人或物的)属性、特征(c)；把…归因于(vt, ~ sth to sb/sth)', '2026-04-21 20:04:00.209556', 'She attributes her success to hard work', null, '她把成功归因于努力工作', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/attribute_1778232582008_e7d63c22.png?sign=1780824582-21ccc05654-0-d61be6d3e837048443c72a66fae9ee8a217b9e1d0fbda056ed7fe49d88ef8d98', null), ('80', 'characteristic', '/ˌkærəktəˈrɪstɪk/', '(人或物的)特征、特色(c, usually pl)；特有的、典型的', '2026-04-21 20:04:00.209556', 'Her smile shows her sweet characteristic.', null, '她的微笑展现了她甜美的特征。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/characteristic_1778232598862_20346bdd.png?sign=1780824599-ac3dc3b58e-0-87a27482a3810671cbac1daf3a90e34a08e83de6a1121bffe181ece55b66c467', null), ('81', 'feature', '/ˈfiːtʃər/', '(地方或事物的)特征、特色；特写；故事片(c)；面貌(c, usually pl)；以…为特色(vt, ~ sb/sth)', '2026-04-21 20:04:00.209556', 'This city features historic buildings', null, '这座城市以历史建筑为特色', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/feature_1778232619817_a66221b1.png?sign=1780824620-5f3e1bc7dc-0-39dc1a9abb894a834e05a1badfcf0752b5aa486bded6d46384b1754f148599a4', null), ('82', 'trait', '/treɪt/', '(某人性格中的)特性、特点；一点(c)', '2026-04-21 20:04:00.209556', 'Her honesty is a valuable trait.', null, '她的诚实是一种宝贵的特性。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/trait_1778232656699_4f857f06.png?sign=1780824657-6e27e0781a-0-0bc3a2b2ed8d4f282c0ab9ea127d63de8296f8682ba983957ebbc5c9a5e7e9b0', null), ('83', 'gender', '/ˈdʒendər/', '性(别)(n)', '2026-04-21 20:04:00.209556', 'The form asks for your gender.', null, '这张表格询问你的性别。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/gender_1778232680491_2d3ed548.png?sign=1780824680-f64c62b20f-0-d1ef34a80b5a5122c1ca195d5566ecf27d0d1ad75ae069f8d0f8bf982d47378a', null), ('84', 'sex', '/seks/', '(人、动、植物的)性(别)(u)', '2026-04-21 20:04:00.209556', 'The doctor discussed the patient''s sex.', null, '医生讨论了患者的性别。', 'https://coze-coding-project.tos.coze.site/coze_storage_7630677478465568811/word-images/sex_1778232703966_9c0c256c.png?sign=1780824704-2dc8183daa-0-602a4b120779cf66cd177be4d239aeab57d55766c09780134ad0ccfb02b3b809', null), ('85', 'age', '/eɪdʒ/', '年龄(段)(n)；时代、时期(c)', '2026-04-21 20:04:00.209556', 'She reached the age of 18 last year.', null, '她去年年满18岁。

